  ('cpa-moex-00741', 'cpa', 'cpa-moex-108-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '會計師出具無保留意見之查核報告，該查核報告之「查核意見之基礎段」中不包含下列何項敘述？ 所依據法令及一般公認審計準則執行查核工作 德規範中有關獨立性之聲明', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "b31a6169dd18", "answer_pdf_sha1": "13aaf559a1eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
